INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "様々なミニゲームをご用意してい\nますよ！\nどのミニゲームで遊びますか？", "2020-02-15 15:00:00", 0, 1000, 1000001, 13, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "楽しいミニゲームをご紹介！\nあなたはどのミニゲームで\n遊びますか？", "2020-02-15 15:00:00", 0, 1000, 1000002, 13, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "こちらは{0}ルピで\n販売中！\nぜひ購入して\n遊んでくださいね！", "2020-02-15 15:00:00", 0, 1001, 1001001, 13, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "動くハートに合わせてタップ！\nシズルさんとエリコさんの\nチョコレートケーキ作りを\nお手伝いしましょう！", "2020-02-15 15:00:00", 0, 1002, 1002001, 12, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "クウカさんを引っ張ってより遠く\nへ飛ばしてあげましょう！\n色々なハプニングでクウカさんに\nエクスタシーを届けましょう！", "2020-02-15 15:00:00", 0, 1003, 1003001, 11, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "左右をタップしてマジムンを倒し\nましょう！\n放て！\n琉球犬アラウンドシュート！", "2020-02-15 15:00:00", 0, 1004, 1004001, 3, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "パネルをタップしてドラゴンズ\nネストのみなさんと一緒に\nしりとり対決をしませんか？\nおしりに「ん」はご法度です。", "2020-02-15 15:00:00", 0, 1005, 1005001, 7, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "素早い動きのネズミに合わせ、\nタップで撃退！\nやる気のリンさんと一緒に\n大切なチーズを守りましょう！", "2020-05-31 12:00:00", 0, 1006, 1006001, 2, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "ミサトさんや部員のみなさんと\nバッティングの特訓ですよ！\nホームランを目指して、ボールを\nタイミングよく打ち返しましょう", "2020-08-15 15:00:00", 0, 1007, 1007001, 4, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "カルミナメダルを使って、\n応援グッズをゲットしましょう！\nメダルはルピを使って\n交換できますよ。\n", "2021-08-31 12:00:00", 0, 1008, 1008001, 6, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "食べたプリンはプリンノート\nで確認してみましょう！\nプリンの材料はルピを使って\n購入できますよ。", "2021-12-18 15:00:00", 0, 1009, 1009001, 13, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "チームでクイズに挑みましょう！\nソロで自分の実力を試すか、マル\nチで仲間と一緒に遊ぶか、好きな\nモードを選んでくださいね♪", "2022-02-15 15:00:00", 0, 1010, 1010001, 4, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "３つのラウンドを駆け抜け、\n総合１位を目指しましょう！\n参加者の皆さんの特徴や、\nＧＰの特徴にも注目です♪", "2022-07-18 15:00:00", 0, 1011, 1011001, 6, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "キャルさん、スズナさんと一緒に\nクイズでお勉強しましょう！\n放課後の教室で二人きりって…\nなんだかドキドキしますね♪", "2023-09-18 15:00:00", 0, 1012, 1012001, 6, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "魔物の討伐任務にいざ行軍！\nエリコさん、マコトさんの\n頼もしい背中は、\n新兵さんたちの憧れですね♪", "2024-04-18 15:00:00", 0, 1013, 1013001, 6, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES ("2030-04-01 14:00:00", "バンディ・シスターズのみなさん\nと戦車バトルに挑戦です！\nパーツやメンバーの組み合わせで\nマシンの特徴が変化しますよ♪", "2024-11-18 15:00:00", 0, 1014, 1014001, 6, 190801);
